# Missing Number — O(n) time, O(1) space
# METHOD 1: Math (Gauss formula)
def missingNumber_math(nums):
    n = len(nums)
    return n * (n + 1) // 2 - sum(nums)

# METHOD 2: XOR
def missingNumber_xor(nums):
    result = len(nums)
    for i, num in enumerate(nums):
        result ^= i ^ num  # XOR with both index and value; pairs cancel
    return result

# WHY XOR works: [0..n] XOR [nums] = missing
# All present numbers appear twice (once as index, once as value) → cancel
